#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long O = (N + 1) / 2; // number of odds
        long long E = N / 2;       // number of evens
        bool ok = true;
        if(O < K) ok = false;
        else if((O & 1LL) != (K & 1LL)) ok = false;
        else if(E + (O - K) / 2 < K) ok = false;
        puts(ok ? "YES" : "NO");
    }
    return 0;
}

