#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        O = (N + 1) // 2  # odds
        E = N // 2        # evens
        ok = True
        if O < K:
            ok = False
        elif (O & 1) != (K & 1):
            ok = False
        elif E + (O - K) // 2 < K:
            ok = False
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

